        function addLicensePlateCopyButtons() {
            $("span[ng-if='yardAsset.vehicleNumber'], span[ng-if='yardAsset.licensePlateIdentifier && yardAsset.licensePlateIdentifier.registrationIdentifier']").each(function () {
                var numberHtml = $(this).html() || "";
                var number = numberHtml.split("<br>")[0].trim();

                if ($(this).parent().parent().find("button.oxy-copy-btn").length < 1) {
                    var textToCopy = (number.split(" ")[0] || "").trim();
                    var copyButton = $("<button>", {
                        class: "oxy-copy-btn superuserTooltip",
                        title: "COPY TO CLIPBOARD",
                        text: "COPY"
                    }).click(function (e) {
                        e.preventDefault();
                        var $btn = $(copyButton);
                        function showCopied() {
                            $btn.text("COPIED!");
                            setTimeout(function () {
                                $btn.text("COPY");
                            }, 2000);
                        }
                        function fallbackCopy(str) {
                            var ta = document.createElement("textarea");
                            ta.value = str;
                            ta.setAttribute("readonly", "");
                            ta.style.position = "fixed";
                            ta.style.left = "-9999px";
                            document.body.appendChild(ta);
                            ta.select();
                            try {
                                document.execCommand("copy");
                                showCopied();
                            } catch (err2) {
                                console.error("Błąd kopiowania:", err2);
                            }
                            document.body.removeChild(ta);
                        }
                        if (navigator.clipboard && typeof navigator.clipboard.writeText === "function") {
                            navigator.clipboard.writeText(textToCopy).then(showCopied).catch(function () {
                                fallbackCopy(textToCopy);
                            });
                        } else {
                            fallbackCopy(textToCopy);
                        }
                    });

                    $(this).parent().parent()
                        .append($("<br>"))
                        .append(copyButton);
                }
            });
        }

